案例代码：
entity example_ENT is
	port (SEL_in: in std_logic;
		DATA_out : out std_logic );
end example_ENT;
architecture behave_ARC of example_ENT is
	--信号在使用前没有赋值，会使此信号被认为是不确定值
	signal S_tmp : std_logic;
	begin
		process (SEL_in，Stmp) begin
		if(SEL_in = '1') then
		DATA_out <= Stmp;
		else
		DATA_OUT <= '0';
		end if;
		end process;
end behave_ARC;

