案例代码：
entity warn_ENT is port (......);
	signal S_a, S_b：std_logic;
	signal S_r：std_logic;
---不应在一个进程中使用多个event contorl段
process（S_a，S_b）
begin
	if rising_edge(S_a)then
	if rising_edge(S_b)then
	S_r = S_a ^ S_b;
	end if;
	end if;
end
end process;
end behave_ARC

