	案例代码-3：
	case (Va & Vb & Vc) is
	  when “100” =>
        base_addr_r[24:0] <= VA + (code_r[7:0] & “000000”);
      when “000” =>
        base_addr_r[24:0] <= VB + (code_r[7:0] & “000000”);
      when “b101” =>
        base_addr_r[24:0] <= VC + (code_r[7:0] & “00000000”);
      when “001”=>
        base_addr_r[24:0] <= VD+ (code_r[7:0] & “00000000”);
      when “010” =>
        base_addr_r[24:0] <= VE+ (code_r[6:0] & “0000000”);
	  --case语句应包含一个when others分支
      WHEN OTHERS=> base_addr_r[24:0] <= base_addr_r[24:0];
    End case;

