案例代码：
entity top_ENT is
port(Clk:in std_logic;
     Rst:in std_logic;
     D_in:in std_logic;
     D_out:out std_logic);
end top_ENT;
architecture behave_ARC of top is
   signal S_Dout1_r, S_Dout_temp_r: std_logic;
begin
   process (Clk, Rst)
   begin
   if Rst= '0' then
     S_Dout_temp_r <= 0;
   elsif Clk’event and clk='1'then ----此处使用时钟信号上升沿
     S_Dout_temp_r <= D_in;
   end if;
   end;
   process (Clk, Rst)
   begin
   if Rst= '0' then
     S_Dout_temp_r <= 0;
   elsif Clk’event and clk='0'then ----此处使用时钟信号下降沿
     D_out <= S_Dout_temp_r;
   end if;
   end;
end behave_ARC;

	案例代码：
	entity example_ENT is
	   port(clk : in std_logic;
             rst: in std_logic;
             sel1: in std_logic;
             sel2: in std_logic;
             din: in std_logic;
             dout: out std_logic);
    end example_ENT;
    architecture behave_ARC of example_ARC is
    signal clk1:std_logic;
    signal clk2: std_logic;
    signal clk_sel: std_logic;
    begin
      clk1 <= sel1 and clk;
      clk2 <= sel2 or clk;
      clk_sel <= clk1 and clk2;--此处的时钟信号在时钟网络上发生了再汇聚
    process(rst,clk_sel)
    begin
      if(rst='0')then
        dout <= ’0’;
      elsif clk_sel’event and clk_sel =’1’ then
        dout <= din;
      end if;
   end process;
   end behave_ARC;

案例代码：
--（程序中状态机进入无效状态后置空操作，可能导致状态机死锁）
singal current_state_r , next_state_r ：std_logic_vector (1 downto 0);
  CONSTANT Cst0 : std_logic_vector (1 downto 0) := “00” ;
  CONSTANT Cst1 : std_logic_vector (1 downto 0) := “01” ;
  CONSTANT Cst2 : std_logic_vector (1 downto 0) := “10” ;
  CONSTANT Cst3 : std_logic_vector (1 downto 0) := “11” ;
	……
  case current_state_r is
	when Cst0=>
	……
	when Cst1=>
	……
	when Cst2=>
	……
--当程序的状态机进入无效状态后执行when others分支，由于程序
--中未对无效状态进行任何处理，状态机一旦进入无效状态则无法再返回到正常的状
--态，导致状态机死锁。
	when others =>null;
end case

案例代码：
--------输出信号反馈驱动同模块内部逻辑------
ENTITY top_ENT IS
	PORT ( A_in：IN STD_LOGIC ；
			B_in：IN STD_LOGIC ；
			CLK ：IN STD_LOGIC ；
			A_r_out：OUT STD_LOGIC;
			B_out：OUT STD_LOGIC）;
end ENTITY;
	ARCHITECTURE behave_ARC OF top_ENT IS
	begin
	B_out <= B_in and A_r_out; ---输出端口A_r_out 在模块内部用来驱动 B_out
	PROCESS (CLK, A_in)
	begin
	if clk'event and clk='1' then
		A_r_out <= A_in;
	end if;
	end process;
	end behave_ARC;

