            d_in:in std_logic;
            d_out: out std_logic);
    end example_ENT;
    architecture behave_ARC of example_ARC is
        signal clk: in std_logic;
    begin
        clk <= a_in and b_in;
    process (clk)
       begin
         if clk’evnt and clk= '1' then
            d_out <= d_in;
		  end if;
    end process;
    end behave_ARC;

