entity top_ENT is port (......);
	......
	signal S_count: std_logic_vector(3 downto 0);
	signal S_flag: std_logic;
	......
process(CLK, RESET_N)
begin
	if (RESET_N='0')THEN
	S_count <=(OTHERS=>'0');
	S_flag <='0';
	else if clk’event and clk='1' then
		if (S_count=16) then --该分支不可达
			S_flag <='1';
		else
			S_count <= S_count + 1;
		end if;
	end if;
end behave_ARC;

